// Rate limiter: max 5 workflows/hora + extract prompt
const staticData = $getWorkflowStaticData('global');
const now = Date.now();
const HOUR = 60 * 60 * 1000;
const MAX_PER_HOUR = 5;

// Clean old entries
if (!staticData.createLog) staticData.createLog = [];
staticData.createLog = staticData.createLog.filter(ts => now - ts < HOUR);

const text = $input.first().json.message.text;
const prompt = text.replace('/create', '').trim();
const chatId = $input.first().json.message.chat.id;

if (!prompt) {
  return [{ json: { error: 'USAGE', message: 'Uso: /create <descripcion del workflow>', chatId } }];
}

if (staticData.createLog.length >= MAX_PER_HOUR) {
  return [{ json: { error: 'RATE_LIMIT', message: `Rate limit: max ${MAX_PER_HOUR} workflows/hora. Intenta en ${Math.ceil((staticData.createLog[0] + HOUR - now) / 60000)} min.`, chatId } }];
}

staticData.createLog.push(now);
return [{ json: { prompt, chatId, error: false } }];

// Schema Validator: valida estructura del workflow generado
try {
  let raw = $input.first().json.text;
  if (raw.includes('```json')) raw = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '');
  else if (raw.includes('```')) raw = raw.replace(/```\n?/g, '');

  const wf = JSON.parse(raw.trim());
  const errors = [];

  if (!wf.name || typeof wf.name !== 'string') errors.push('Falta nombre del workflow');
  if (!Array.isArray(wf.nodes) || wf.nodes.length === 0) errors.push('Falta array de nodos');
  if (!wf.connections || typeof wf.connections !== 'object') errors.push('Falta objeto de conexiones');

  const allowedTypes = [
    'n8n-nodes-base.scheduleTrigger', 'n8n-nodes-base.webhook', 'n8n-nodes-base.telegramTrigger',
    'n8n-nodes-base.emailTrigger', 'n8n-nodes-base.if', 'n8n-nodes-base.switch',
    'n8n-nodes-base.code', 'n8n-nodes-base.merge', 'n8n-nodes-base.splitInBatches',
    'n8n-nodes-base.wait', 'n8n-nodes-base.httpRequest', 'n8n-nodes-base.telegram',
    'n8n-nodes-base.ssh', 'n8n-nodes-base.readWriteFile', 'n8n-nodes-base.emailSend',
    '@n8n/n8n-nodes-langchain.chainLlm', '@n8n/n8n-nodes-langchain.lmChatGroq',
    '@n8n/n8n-nodes-langchain.lmChatOpenAi', 'n8n-nodes-base.set',
    'n8n-nodes-base.dateTime', 'n8n-nodes-base.crypto', 'n8n-nodes-base.errorTrigger',
    'n8n-nodes-base.noOp', 'n8n-nodes-base.rssFeedRead'
  ];

  if (wf.nodes) {
    if (wf.nodes.length > 20) errors.push('Demasiados nodos (max 20): ' + wf.nodes.length);
    const hasTrigger = wf.nodes.some(n => n.type && (n.type.includes('Trigger') || n.type.includes('trigger') || n.type.includes('webhook')));
    if (!hasTrigger) errors.push('No tiene nodo trigger');
    for (const node of wf.nodes) {
      if (!node.type) { errors.push('Nodo sin tipo: ' + JSON.stringify(node).substring(0, 100)); continue; }
      if (!allowedTypes.includes(node.type) && !node.type.startsWith('@n8n/')) {
        errors.push('Nodo no permitido: ' + node.type);
      }
      const nodeStr = JSON.stringify(node);
      if (nodeStr.includes('sk-') || nodeStr.includes('gsk_') || nodeStr.includes('Bearer ')) {
        errors.push('Credenciales hardcodeadas detectadas en nodo: ' + (node.name || node.type));
      }
    }
  }

  const chatId = $('ExtractValidateRateLimit').first().json.chatId;

  if (errors.length > 0) {
    return [{ json: { valid: false, errors, workflowName: wf.name || 'Sin nombre', nodeCount: (wf.nodes || []).length, chatId } }];
  }

  const nodeNames = wf.nodes.map(n => n.name || n.type).join(', ');
  return [{ json: { valid: true, workflow: wf, workflowName: wf.name, nodeCount: wf.nodes.length, nodeNames, chatId } }];

} catch (e) {
  const chatId = $('ExtractValidateRateLimit').first().json.chatId;
  return [{ json: { valid: false, errors: ['JSON invalido: ' + e.message], workflowName: 'Error', nodeCount: 0, chatId } }];
}

