// Check if user confirmed or cancelled
const body = $input.first().json.body || $input.first().json;
const text = (body.message?.text || body.text || '').trim().toLowerCase();

// Get stored workflow from earlier in the chain
const schemaData = $('IfSchemaValid').first().json;
const workflowData = schemaData.workflow;
const chatId = schemaData.chatId;

if (text === '/confirm' || text === 'confirm') {
  return [{ json: { confirmed: true, workflow: workflowData, chatId } }];
} else {
  return [{ json: { confirmed: false, reason: text || 'No confirmation received', chatId } }];
}

